UPDATE respostas_lacunas_cerd_iii 
SET justificativa_avaliacao = 'Reversão da política de paralisia nas demarcações a partir de 2023, com criação do MPI. Conforme dados da FUNAI, existem 646 Terras Indígenas registradas, das quais 496 estão regularizadas. A dívida histórica permanece com os processos pendentes de demarcação e homologação.'
WHERE paragrafo_cerd_iii = '20';